import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    // Get full problem details
    const problem = await problemsClient.getProblem({
      problemId: input.problemId
    });

    let report = {
      problemId: problem.id,
      title: problem.title,
      status: problem.status,
      severity: problem.severityLevel,
      impactLevel: problem.impactLevel,
      startTime: problem.startTime,
      endTime: problem.endTime,
      duration: problem.endTime ? problem.endTime - problem.startTime : Date.now() - problem.startTime
    };

    // Add affected users if requested
    if (input.includeAffectedUsers === 'true' && problem.impactAnalysis) {
      let totalUsers = 0;
      problem.impactAnalysis.impacts.forEach(impact => {
        totalUsers += impact.estimatedAffectedUsers || 0;
      });
      report.affectedUsers = totalUsers;
      report.impactAnalysis = problem.impactAnalysis;
    }

    // Add timeline if requested
    if (input.includeTimeline === 'true') {
      report.eventSummary = problem.eventSummary || 'No timeline available';
    }

    // Add suggested fixes if requested
    if (input.includeSuggestedFixes === 'true') {
      report.remediation = problem.recommendations || [];
    }

    console.log(`Generated report for problem ${input.problemId}`);

    return report;
  } catch (error) {
    console.error('Error generating report:', error);
    throw new Error(`Failed to generate report: ${error}`);
  }
}
